// Runtime configuration — intentionally NOT bundled.
//
// This file is loaded as a static asset before the app bundle, so the SAME
// shell build can be pointed at different remote deployments per environment
// (dev / staging / prod) just by swapping this file at deploy time. No rebuild
// required. In a real platform this is generated by the deploy pipeline or
// served by a config service.
window.__FPK_CONFIG__ = {
  environment: "development",
  remotes: {
    dashboard: "http://localhost:3001/remoteEntry.js",
    analytics: "http://localhost:3002/remoteEntry.js",
    settings: "http://localhost:3003/remoteEntry.js"
  }
};
